#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
int t,n,l;
string s[2005];
unordered_map<string,bool> mp;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>t;
	for(int num=1;num<=t;num++)
	{
		mp.clear();
		cin>>n>>l;
		for(int i=1;i<=n;i++)
		{
			cin>>s[i];
			mp[s[i]]=1;
		}
		int cnt=10000;
		while(cnt--)
		{
			string tmp="";
			for(int i=1;i<=l;i++)
			{
				tmp+=s[(rand()%n)+1][i-1];
			}
			if(!mp.count(tmp))
			{
				cout<<"Case #"<<num<<": "<<tmp<<'\n';
				goto end;
			}
		}
		cout<<"Case #"<<num<<": -\n";
		end: ;
	}
	return 0;
}
